class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        const long long MOD = 1'000'000'007;
        vector<long long> dp(n + 1, 0);
        dp[1] = 1;
        for (int day = 2; day <= n; ++day) {
            long long share = 0;
            for (int prev = day - forget + 1; prev <= day - delay; ++prev) {
                if (prev >= 1) {
                    share = (share + dp[prev]) % MOD;
                }
            }
            dp[day] = share;
        }
        long long res = 0;
        for (int day = n - forget + 1; day <= n; ++day) {
            if (day >= 1) {
                res = (res + dp[day]) % MOD;
            }
        }
        return static_cast<int>(res);
    }
};
```
efficiency: HIGH
time complexity: O(n * forget)
space complexity: O(n)
energy implications: LOW
explanation: Uses a dynamic-programming array dp[day] to count new people who learn the secret on each day. For each day, the number of new people equals the sum of all people who are still active (not forgotten) and have waited at least delay days. The final answer is the sum of dp over the last forget days.

